  supabase = await createClient()
  user = await supabase.auth.getUser()
  if user → redirect('/events')
  return (
    <div>
      <Header />
      <main>
        히어로 섹션: '모임' 제목 + 설명 + Link href='/auth/login' '시작하기'
        기능 소개: 이벤트 관리 / 참여 응답 / 공지사항 카드 3개
      </main>
      <Footer />
    </div>
  )
}

