export default async function EventsPage() {
  supabase = await createClient()
  { data: { user } } = await supabase.auth.getUser()
  if (!user) redirect('/auth/login')
  return <div><h1>이벤트 목록</h1><p>이벤트 목록이 여기에 표시됩니다.</p></div>
}

